output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?film WHERE {
  ?film wdt:P31 wd:Q11424 ; wdt:P17 wd:Q35 ; wdt:P1411 wd:Q1320735 .
}

args.sparql:
SELECT DISTINCT ?film WHERE {
  ?film wdt:P17 wd:Q35 .
  ?film wdt:P1625 wd:Q5761776 .
  ?film wdt:P1626 wd:Q5056271
}

SELECT DISTINCT ?film WHERE {
  ?film wdt:P17 wd:Q35 .
  ?film p:P1625 [
    ps:P1625 wd:Q54;
    pq:P1626 wd:Q85523
  ]
}

SELECT DISTINCT ?film WHERE {
  ?film wdt:P17 wd:Q35 .
  ?film wdt:P1411 wd:Q1320735 .
  ?film wdt:P577 ?releaseDate .
  FILTER (YEAR(?releaseDate) = 1981)
}

SELECT DISTINCT ?film ?releaseDate WHERE {
  ?film wdt:P31 wd:Q11424 .
  ?film wdt:P17 wd:Q35 .
  ?film wdt:P1411 wd:Q5761776 .
  ?film wdt:P577 ?releaseDate
}

SELECT DISTINCT ?film WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P17 wd:Q35;
        wdt:P1411 ?ceremony.
  ?ceremony wdt:P1625 wd:Q5761776;
            wdt:P585 ?date.
  FILTER(YEAR(?date) = 1982)
}

SELECT DISTINCT ?film WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P17 wd:Q35;
        wdt:P1411 wd:Q2356947.
  ?film wdt:P577 ?releaseDate.
  FILTER (YEAR(?releaseDate) >= 1981 && YEAR(?releaseDate) <= 1981)
}

SELECT DISTINCT ?film ?label WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P17 wd:Q35;
        wdt:P1411 wd:Q5761776.
  ?film rdfs:label ?label.
  FILTER(LANG(?label) = 'en')
  ?film wdt:P577 ?releaseDate.
  FILTER(YEAR(?releaseDate) = 1981)
}

SELECT DISTINCT ?film ?label ?year WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P17 wd:Q35;
        wdt:P1411 wd:Q2356947;
        wdt:P577 ?releaseDate.
  ?film rdfs:label ?label.
  FILTER(LANG(?label) = 'en')
  BIND(YEAR(?releaseDate) AS ?year)
}

SELECT DISTINCT ?film ?label WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P17 wd:Q35;
        p:P1625 [ ps:P1625 wd:Q2371168; pq:P1625 wd:Q2356947 ].
  ?film rdfs:label ?label.
  FILTER(LANG(?label) = 'en')
}

SELECT DISTINCT ?film WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P17 wd:Q35;
        wdt:P1411 wd:Q1320735.
}
